targets.expr:
sum(
    sum(
        (
            {__name__=~"codefresh_classic_build_step_completion_timestamp(_seconds)*$", cf_classic_build_id="$cf_classic_build_id"}
            -
            {__name__=~"codefresh_classic_build_step_start_timestamp(_seconds)*$", cf_classic_build_id="$cf_classic_build_id"}
        )
        or
        (
            time()
            -
            {__name__=~"codefresh_classic_build_step_start_timestamp(_seconds)*$", cf_classic_build_id="$cf_classic_build_id"}
        )
    ) by (cf_classic_build_id, cf_classic_build_step_name)
    * on(cf_classic_build_id, cf_classic_build_step_name)
    sum(codefresh_classic_build_step_info{cf_classic_build_id="$cf_classic_build_id", cf_classic_build_step_type=~"$pre_step_type"} > 0) by (cf_classic_build_id, cf_classic_build_step_name)
) by (cf_classic_build_step_name)

sum(
    sum(
        (
            {__name__=~"codefresh_classic_build_step_completion_timestamp(_seconds)*$", cf_classic_build_id="$cf_classic_build_id"}
