    ) by (cf_classic_build_id, cf_classic_build_step_name)
    * on(cf_classic_build_id, cf_classic_build_step_name)
    sum(codefresh_classic_build_step_info{cf_classic_build_id="$cf_classic_build_id", cf_classic_build_step_type=~"$post_step_type"} > 0) by (cf_classic_build_id, cf_classic_build_step_name)
) by (cf_classic_build_step_name)

